import os
from flask import Flask, request, jsonify
import pymysql

app = Flask(__name__)

# Cloud SQL instance connection name and database credentials
INSTANCE_CONNECTION_NAME = 'your-project:your-region:your-instance'
DB_USER = 'your-username'
DB_PASSWORD = 'your-password'

def get_db():
    try:
        conn = pymysql.connect(
            user=DB_USER,
            password=DB_PASSWORD,
            host=INSTANCE_CONNECTION_NAME.split(':')[0],
            database='your-database',
            unix_socket=True
        )
        return conn
    except Exception as e:
        print(f"Error connecting to Cloud SQL: {e}")
        return None

@app.route('/search', methods=['GET'])
def search():
    try:
        params = request.args.to_dict()
        
        # Construct dynamic SQL query using string concatenation
        query = "SELECT * FROM your-table WHERE "
        conditions = []
        
        for key, value in params.items():
            if value:
                conditions.append(f"{key} LIKE '%{value}%'")
        
        if conditions:
            query += ' AND '.join(conditions)
        else:
            query = "SELECT * FROM your-table"
        
        conn = get_db()
        with conn.cursor() as cur:
            cur.execute(query)
            results = cur.fetchall()
            
            # Convert results to JSON
            result_json = []
            for row in results:
                result_json.append(dict(zip([c[0] for c in cur.description], row)))
            
            return jsonify(result_json)
    
    except Exception as e:
        print(f"Error executing search query: {e}")
        return jsonify({'error': 'Internal Server Error'}), 500

if __name__ == '__main__':
    app.run(debug=True)